+pub(crate) fn rebuild_fts_via_rusqlite(db_path: &Path) -> Result<usize> {
+    {
+        let conn = rusqlite::Connection::open(db_path).with_context(|| {
+            format!(
+                "opening rusqlite db at {} for FTS schema cleanup",
+                db_path.display()
